 1	import { ChartLegendTooltip, createContainer } from '@patternfly/react-charts';
 2	import React from 'react';
 3	import { ChartDataPoint, LegendDataItem } from '../../utils/metrics-helper';
 4	
 5	const CursorVoronoiContainer = createContainer('voronoi', 'cursor');
 6	
 7	const CHAR_AVG_WIDTH = 7.5;
 8	const FLYOUT_PADDING = 40;
 9	const TITLE_ESTIMATED_LEN = 28;
10	const VALUE_ESTIMATED_LEN = 12;
11	
12	export const chartVoronoi = (legendData: LegendDataItem[], f: (v: number) => string) => {
13	  const tooltipData = legendData.map(item => ({ ...item, name: item.tooltipName || item.name }));
14	  const maxNameLen = Math.max(0, ...tooltipData.map(d => (d.name || '').length));
15	  const legendWidth = (maxNameLen + VALUE_ESTIMATED_LEN + 2) * CHAR_AVG_WIDTH;
16	  const titleWidth = TITLE_ESTIMATED_LEN * CHAR_AVG_WIDTH;
17	  const flyoutWidth = Math.max(titleWidth, legendWidth) + FLYOUT_PADDING;
18	
19	  return (
20	    <CursorVoronoiContainer
21	      cursorDimension="x"
22	      labels={(dp: { datum: ChartDataPoint }) => {
23	        return dp.datum.y || dp.datum.y === 0 ? f(dp.datum.y) : 'n/a';
24	      }}
25	      labelComponent={
26	        <ChartLegendTooltip
27	          legendData={tooltipData}
28	          // eslint-disable-next-line @typescript-eslint/no-explicit-any
29	          title={(cb: any) => cb.datum?.date}
30	          flyoutWidth={flyoutWidth}
31	        />
32	      }
33	      mouseFollowTooltips
34	      voronoiDimension="x"
35	      voronoiPadding={50}
36	    />
37	  );
38	};

